import{c as a,Q as t,j as s,m as n}from"./chunks/framework.CTNaDwNv.js";const u=JSON.parse('{"title":"Configuration","description":"","frontmatter":{},"headers":[],"relativePath":"guide/configuration.md","filePath":"guide/configuration.md","lastUpdated":1779853631000}'),o={name:"guide/configuration.md"};function i(l,e,d,c,p,r){return t(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h1><p>Everything <code>agent_api</code> exposes is convar-driven. All convars are read once at resource start; restart <code>agent_api</code> to pick up a change.</p><h2 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to &quot;Core&quot;">​</a></h2><div class="language-cfg vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cfg</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>set agent_api_token                       &quot;&quot;          # blank = auto-generate</span></span>
<span class="line"><span>set agent_api_readonly                    false       # closes every mutating tool</span></span>
<span class="line"><span>set agent_api_root                        &quot;resources/[agent]&quot;</span></span>
<span class="line"><span>set agent_api_allow_write_paths           &quot;&quot;          # csv, extra write roots</span></span>
<span class="line"><span>set agent_api_allow_control_paths         &quot;&quot;          # csv, extra lifecycle roots</span></span></code></pre></div><table tabindex="0"><thead><tr><th>convar</th><th>default</th><th>meaning</th></tr></thead><tbody><tr><td><code>agent_api_token</code></td><td>(blank)</td><td>bearer token in <code>x-agent-token</code> header. Blank → generate + persist to <code>dist/.agent_token</code></td></tr><tr><td><code>agent_api_readonly</code></td><td><code>false</code></td><td>when <code>true</code>, every mutating tool (write, ensure/start/..., shell, ESX add_money, native verbs not starting with Get/Has/Is/...) refuses</td></tr><tr><td><code>agent_api_root</code></td><td><code>resources/[agent]</code></td><td>sandbox root for writes + lifecycle</td></tr><tr><td><code>agent_api_allow_write_paths</code></td><td>(none)</td><td>additional write roots (csv)</td></tr><tr><td><code>agent_api_allow_control_paths</code></td><td>(none)</td><td>additional lifecycle roots (csv)</td></tr></tbody></table><h2 id="buffers-and-limits" tabindex="-1">Buffers and limits <a class="header-anchor" href="#buffers-and-limits" aria-label="Permalink to &quot;Buffers and limits&quot;">​</a></h2><div class="language-cfg vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cfg</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>set agent_api_console_buffer_lines        2000</span></span>
<span class="line"><span>set agent_api_max_file_bytes              2097152     # 2 MB</span></span>
<span class="line"><span>set agent_api_extra_write_extensions      &quot;&quot;          # csv, e.g. &quot;.webp,.lock&quot;</span></span>
<span class="line"><span>set agent_api_rate_per_minute             120</span></span></code></pre></div><table tabindex="0"><thead><tr><th>convar</th><th>default</th><th>meaning</th></tr></thead><tbody><tr><td><code>agent_api_console_buffer_lines</code></td><td><code>2000</code></td><td>size of the in-memory ring buffer used by <code>tail_console</code></td></tr><tr><td><code>agent_api_max_file_bytes</code></td><td><code>2_097_152</code></td><td>hard cap on <code>read_file</code> / <code>write_file</code></td></tr><tr><td><code>agent_api_extra_write_extensions</code></td><td>(none)</td><td>append extensions to the writable allowlist (csv, with or without the leading <code>.</code>)</td></tr><tr><td><code>agent_api_rate_per_minute</code></td><td><code>120</code></td><td>token-bucket cap per <code>x-agent-token</code> hash; over → <code>429 RATE_LIMITED</code></td></tr></tbody></table><h2 id="live-client-testing" tabindex="-1">Live client testing <a class="header-anchor" href="#live-client-testing" aria-label="Permalink to &quot;Live client testing&quot;">​</a></h2><div class="language-cfg vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cfg</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>set agent_api_test_session_ttl_seconds    1800</span></span>
<span class="line"><span>set agent_api_test_max_subjects           4</span></span>
<span class="line"><span>set agent_api_client_blocked_natives      &quot;&quot;          # csv</span></span></code></pre></div><table tabindex="0"><thead><tr><th>convar</th><th>default</th><th>meaning</th></tr></thead><tbody><tr><td><code>agent_api_test_session_ttl_seconds</code></td><td><code>1800</code></td><td>how long <code>/agent_test_optin</code> stays valid</td></tr><tr><td><code>agent_api_test_max_subjects</code></td><td><code>4</code></td><td>size of the active subject pool</td></tr><tr><td><code>agent_api_client_blocked_natives</code></td><td>(none)</td><td>per-name blocklist enforced before <code>client_call_native</code></td></tr></tbody></table><h2 id="server-side-natives" tabindex="-1">Server-side natives <a class="header-anchor" href="#server-side-natives" aria-label="Permalink to &quot;Server-side natives&quot;">​</a></h2><div class="language-cfg vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cfg</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>set agent_api_server_blocked_natives      &quot;&quot;          # csv</span></span></code></pre></div><p>In addition to the user blocklist, <code>server_call_native</code> carries a built-in danger list that always refuses: <code>DropPlayer</code>, <code>ExecuteCommand</code>, <code>StopResource</code>, <code>StartResource</code>, <code>ScheduleResourceTick</code>, <code>PrintStructuredTrace</code>, <code>CancelEvent</code>, <code>TempBanPlayer</code>, <code>BanPlayer</code>. Use the dedicated tools (<code>run_command</code>, <code>ensure_resource</code>, etc.) for those instead.</p><h2 id="shell" tabindex="-1">Shell <a class="header-anchor" href="#shell" aria-label="Permalink to &quot;Shell&quot;">​</a></h2><div class="language-cfg vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cfg</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>set agent_api_shell_allowed_commands      &quot;&quot;          # csv; default = npm,npx,pnpm,yarn,bun,vite,git,node</span></span>
<span class="line"><span>set agent_api_node_binary                 &quot;node&quot;      # used by screenshot_nui spawn</span></span></code></pre></div><p>If <code>agent_api_shell_allowed_commands</code> is non-empty it <strong>replaces</strong> the default — set it to your full allowlist, not just additions.</p><h2 id="plugins" tabindex="-1">Plugins <a class="header-anchor" href="#plugins" aria-label="Permalink to &quot;Plugins&quot;">​</a></h2><div class="language-cfg vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cfg</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>set agent_api_plugin_esx_enabled          auto        # auto | true | false</span></span>
<span class="line"><span>set agent_api_plugin_oxlib_enabled        auto</span></span>
<span class="line"><span>set agent_api_plugin_oxmysql_enabled      auto</span></span></code></pre></div><ul><li><code>auto</code> — load only if the target resource is started. Default.</li><li><code>true</code> / <code>force</code> — load even if detection fails.</li><li><code>false</code> — never load, even if detected.</li></ul><h3 id="plugin-specific" tabindex="-1">Plugin-specific <a class="header-anchor" href="#plugin-specific" aria-label="Permalink to &quot;Plugin-specific&quot;">​</a></h3><div class="language-cfg vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cfg</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>set agent_api_plugin_esx_blocked_methods           &quot;&quot;          # csv of xPlayer/ESX method names to refuse</span></span>
<span class="line"><span>set agent_api_plugin_oxlib_blocked_methods         &quot;&quot;          # csv of ox_lib server export names to refuse</span></span>
<span class="line"><span>set agent_api_plugin_oxmysql_readonly              true        # SELECT-only</span></span>
<span class="line"><span>set agent_api_plugin_oxmysql_allow_statements      &quot;SELECT&quot;    # csv, uppercase, e.g. &quot;SELECT,INSERT,UPDATE&quot;</span></span></code></pre></div><h2 id="full-example-server-cfg-block" tabindex="-1">Full example <code>server.cfg</code> block <a class="header-anchor" href="#full-example-server-cfg-block" aria-label="Permalink to &quot;Full example \`server.cfg\` block&quot;">​</a></h2><div class="language-cfg vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cfg</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># agent_api</span></span>
<span class="line"><span>set agent_api_token                       &quot;&quot;</span></span>
<span class="line"><span>set agent_api_readonly                    false</span></span>
<span class="line"><span>set agent_api_root                        &quot;resources/[agent]&quot;</span></span>
<span class="line"><span>set agent_api_rate_per_minute             120</span></span>
<span class="line"><span>set agent_api_test_session_ttl_seconds    1800</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Open oxmysql for full CRUD on app-owned tables only</span></span>
<span class="line"><span>set agent_api_plugin_oxmysql_readonly         false</span></span>
<span class="line"><span>set agent_api_plugin_oxmysql_allow_statements &quot;SELECT,INSERT,UPDATE,DELETE&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># ACE</span></span>
<span class="line"><span>add_ace resource.agent_api command.ensure  allow</span></span>
<span class="line"><span>add_ace resource.agent_api command.start   allow</span></span>
<span class="line"><span>add_ace resource.agent_api command.stop    allow</span></span>
<span class="line"><span>add_ace resource.agent_api command.restart allow</span></span>
<span class="line"><span>add_ace resource.agent_api command.refresh allow</span></span>
<span class="line"><span>add_ace resource.agent_api command.say     allow</span></span>
<span class="line"><span></span></span>
<span class="line"><span>ensure agent_api</span></span></code></pre></div>`,24)])])}const g=a(o,[["render",i]]);export{u as __pageData,g as default};
